const resume = $input.item.json;
if (!resume || !resume[0] || !resume[0].extracted_text) {
  return [{ json: { skip: true, reason: 'No resume found', user_id: $('🔄 Loop Users').item.json.user_id } }];
}
return [{ json: { hasResume: true, resumeId: resume[0].id, resumeText: resume[0].extracted_text, fileUrl: resume[0].file_url, storagePath: resume[0].storage_path, user_id: $('🔄 Loop Users').item.json.user_id } }];

const results = $input.all();
const jobs = [];
const seen = new Set();

function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(li|p|div|h[1-6])[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

for (const item of results) {
  const j = item.json;
  const jobLink = j.link || j.jobUrl || j.url || '';
  if (seen.has(jobLink) || !jobLink) continue;

  const postedAt = j.postedAt || '';
  const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10);
  if (postedAt && postedAt < sevenDaysAgo) continue;

  const jobDescription = j.descriptionHtml
    ? stripHtml(j.descriptionHtml)
    : (j.descriptionText || '');
  if (!jobDescription || jobDescription.length < 50) continue;

  jobs.push({
    title:          j.title       || 'No Title',
    company:        j.companyName || 'Unknown Company',
    location:       j.location    || 'Unknown',
    postedAt,
    employmentType: j.employmentType || '',
    seniorityLevel: j.seniorityLevel || '',
    jobLink,
    jobDescription
  });

  seen.add(jobLink);
  if (jobs.length >= 20) break;
}

return jobs.map(job => ({ json: job }));

const allJobs = $input.all();
const config = $('⚙️ Config').first().json;
const supabaseUrl = config.supabaseUrl;
const supabaseKey = config.supabaseKey;

async function jobExists(jobUrl) {
  try {
    const r = await fetch(
      `${supabaseUrl}/rest/v1/jobs?apply_link=eq.${encodeURIComponent(jobUrl)}&select=id`,
      { headers: { 'apikey': supabaseKey, 'Authorization': `Bearer ${supabaseKey}` } }
    );
    const data = await r.json();
    return data.length > 0;
  } catch { return false; }
}

const checks = await Promise.all(allJobs.map(j => jobExists(j.json.jobLink)));
const newJobs = allJobs.filter((_, i) => !checks[i]);

return newJobs.slice(0, 10);

const saved = $json;
const orig  = $('🏆 Limit to 5 Jobs').item.json;
return [{ json: {
  jobId:          saved[0]?.id || saved.id || '',
  title:          orig.title,
  company:        orig.company,
  jobLink:        orig.jobLink,
  jobDescription: orig.jobDescription,
