const raw = ($json.output ?? '').trim();

function esc(s) {
  return String(s ?? '')
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/&/g, '\\&')
    .replace(/%/g, '\\%')
    .replace(/\$/g, '\\$')
    .replace(/#/g, '\\#')
    .replace(/_/g, '\\_')
    .replace(/\{/g, '\\{')
    .replace(/\}/g, '\\}')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}');
}

function section(text, header) {
  const re = new RegExp('(?:^|\\n)' + header.replace(/ /g, '\\s+') + '\\s*\\n([\\s\\S]*?)(?=\\n[A-Z][A-Z ]{2,}\\s*\\n|$)', 'i');
  const m = text.match(re);
  return m ? m[1].trim() : '';
}

const nameRaw       = section(raw, 'NAME');
const contactRaw    = section(raw, 'CONTACT');
const summaryRaw    = section(raw, 'SUMMARY');
const experienceRaw = section(raw, 'PROFESSIONAL EXPERIENCE');
const educationRaw  = section(raw, 'EDUCATION');
const skillsRaw     = section(raw, 'SKILLS');

const fullName  = (nameRaw.split('\n')[0] || 'Candidate').trim();
const parts     = fullName.split(' ');
const firstName = esc(parts.length > 1 ? parts.slice(0, -1).join(' ') : fullName);
const lastName  = esc(parts.length > 1 ? parts[parts.length - 1] : '');

const tokens    = contactRaw.replace(/\n/g, ' | ').split('|').map(s => s.trim()).filter(Boolean);
const email     = esc(tokens.find(p => p.includes('@')) ?? '');
const phone     = esc(tokens.find(p => /\d{3}[-.\s]\d{3}/.test(p)) ?? '');
const liRaw     = tokens.find(p => /linkedin/i.test(p)) ?? '';
const linkedin  = esc(liRaw.replace(/^https?:\/\//i, '').replace(/^www\./i, '').replace(/^linkedin\.com\/in\//i, '').replace(/\/+$/, ''));
const city      = esc(tokens.find(p => !p.includes('@') && !/\d{3}[-.\s]\d{3}/.test(p) && !/linkedin/i.test(p)) ?? '');
const summary   = esc(summaryRaw.replace(/\n/g, ' ').trim());

function buildExp(text) {
  if (!text) return '\\cvitem{}{}';
  const lines = text.split('\n');
  const blocks = [];
  let cur = [];
  for (const l of lines) {
    const t = l.trim();
    if (!t) continue;
    if (t.includes('|') && !t.startsWith('-') && cur.length) { blocks.push(cur); cur = []; }
    cur.push(t);
  }
  if (cur.length) blocks.push(cur);
  return blocks.map(b => {
    const [co, loc]     = (b[0]||'').split('|').map(s => s.trim());
    const [ti, dates]   = (b[1]||'').split('|').map(s => s.trim());
    const bullets       = b.slice(2).filter(l => l.startsWith('- '));
    let out = `\n\\cventry{${esc(dates)}}{${esc(ti)}}{${esc(co)}}{${esc(loc)}}{}{
`;
    if (bullets.length) {
      out += '  \\begin{itemize}\n' + bullets.map(b => `    \\item ${esc(b.replace(/^-\s+/,''))}`).join('\n') + '\n  \\end{itemize}\n';
    }
    return out + '}';
  }).join('\n') || '\\cvitem{}{}';
}

function buildEdu(text) {
  if (!text) return '\\cvitem{}{}';
  const lines = text.split('\n').map(l => l.trim()).filter(l => l && !l.startsWith('-'));
  let out = '';
  for (let i = 0; i + 1 < lines.length; i += 2) {
    const [sch, loc] = lines[i].split('|').map(s => s.trim());
    const [deg, dt]  = lines[i+1].split('|').map(s => s.trim());
    out += `\\cventry{${esc(dt)}}{${esc(deg)}}{${esc(sch)}}{${esc(loc)}}{}{}\n`;
  }
  return out || '\\cvitem{}{}';
}

function buildSkills(text) {
  if (!text) return '\\cvitem{}{}';
  return text.split('\n').map(l => l.trim()).filter(Boolean).map(l => {
    const clean = l.replace(/^-\s*/,'');
    const ci = clean.indexOf(':');
    return ci > 0
      ? `\\cvitem{${esc(clean.slice(0,ci).trim())}}{${esc(clean.slice(ci+1).trim())}}`
      : `\\cvitem{}{${esc(clean)}}`;
  }).join('\n');
}

const latex = `\\documentclass[11pt,a4paper,sans]{moderncv}
\\moderncvstyle{banking}
\\moderncvcolor{blue}
\\usepackage[scale=0.88]{geometry}
\\nopagenumbers{}

\\name{${firstName}}{${lastName}}
\\phone[mobile]{${phone}}
\\email{${email}}
\\social[linkedin]{${linkedin}}
\\address{${city}}{}{}

\\begin{document}
\\makecvtitle

\\section{Summary}
\\cvitem{}{${summary}}

\\section{Professional Experience}
${buildExp(experienceRaw)}

\\section{Education}
${buildEdu(educationRaw)}

\\section{Skills}
${buildSkills(skillsRaw)}

\\end{document}
`;

const src = $('🔀 Merge Job + Resume').item.json;
return [{ json: { latex, output: $json.output, company: src.company, title: src.title, jobLink: src.jobLink, jobId: src.jobId, userId: src.userId, postedAt: src.postedAt } }];

const src = $('📝 Build LaTeX Resume').item.json;
const safe = s => (s||'').replace(/[\/\\:*?"<>|]/g,'').slice(0,60);
const docTitle = `${safe(src.title)}_${safe(src.company)}_${(src.postedAt||new Date().toISOString()).slice(0,10)}`;
return [{ json: { docTitle, company: src.company, title: src.title, jobLink: src.jobLink, jobId: src.jobId, userId: src.userId, postedAt: src.postedAt, output: src.output }, binary: { data: $input.item.binary.pdfData } }];

const pdfId       = $json.id ?? '';
const pdfLink     = pdfId ? `https://drive.google.com/file/d/${pdfId}/view` : '';
const pdfDownload = pdfId ? `https://drive.google.com/uc?export=download&id=${pdfId}` : '';
const meta        = $('🏷️ Prep PDF Metadata').item.json;

return [{ json: {
  pdfId, pdfLink, pdfDownload,
  jobId:    meta.jobId,
  userId:   meta.userId,
  title:    meta.title,
  company:  meta.company,
  jobLink:  meta.jobLink,
  postedAt: meta.postedAt
} }];

const items       = $('🔗 Extract PDF Link').all();
const today       = new Date().toISOString().slice(0, 10);
const esc         = s => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

let rows = items.map(item => {
  const j = item.json;
  return `<tr>
    <td style="padding:10px;border-bottom:1px solid #eee;font-weight:700;">${esc(j.company)}</td>
    <td style="padding:10px;border-bottom:1px solid #eee;">${esc(j.title)}</td>
    <td style="padding:10px;border-bottom:1px solid #eee;">${esc(j.postedAt)}</td>
    <td style="padding:10px;border-bottom:1px solid #eee;"><a href="${j.jobLink}">🔗 Apply</a></td>
    <td style="padding:10px;border-bottom:1px solid #eee;"><a href="${j.pdfLink}">📄 Resume PDF</a></td>
  </tr>`;
}).join('');

const html = `<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;">
  <h2 style="color:#2563EB;">🚀 JobPilot Daily Report — ${today}</h2>
  <p>Your AI-optimized resumes are ready. <strong>${items.length} new jobs</strong> found today.</p>
  <table style="border-collapse:collapse;width:100%;">
    <thead><tr style="background:#f5f5f5;">
      <th style="padding:10px;text-align:left;">Company</th>
      <th style="padding:10px;text-align:left;">Role</th>
      <th style="padding:10px;text-align:left;">Posted</th>
      <th style="padding:10px;text-align:left;">Job Link</th>
      <th style="padding:10px;text-align:left;">Optimized Resume</th>
    </tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <p style="color:#aaa;font-size:11px;margin-top:20px;">Sent by JobPilot AI — ${today}</p>
</div>`;

return [{ json: { subject: `🎯 JobPilot: ${items.length} New Jobs + Resumes Ready — ${today}`, body: html } }];
